#!/bin/bash

echo '[TASK] Generating gitignore...'
echo '[INFO] You will be asked your name, email and github account email.'
read -p 'Your name:'
NAME=$REPLY
read -p 'Your email:'
EMAIL=$REPLY
read -p 'Your Github email:'
GITHUB_EMAIL=$REPLY
cat <<EOF > .gitconfig
  # This file was generated by generate_gitignore in ~/.dotfiles/scripts
  # Better edit that one!
  [user]
    name = $NAME
    email = $EMAIL
  [color]
    ui = auto
  [core]
    excludesfile = $HOME/.gitignore
    editor = code
  [apply]
    whitespace = nowarn
  [branch]
    autosetuprebase = always
  [grep]
    lineNumber = true
  [log]
    date = relative
    decorate = short
  [merge]
    ff = false
  [push]
    default = simple
  [github]
    user = $GITHUB_EMAIL
  [credential]
    helper = osxkeychain
  [help]
    autocorrect = 1
EOF
echo '[INFO] Generated gitignore successfully in dotfiles folder.'
